    messages = slack_data.get('messages', {}).get(comp_urgent_id, [])
    # Extract key from "Jira: KEY" field in B-4 template, falling back to any
    # non-OPS, non-INTL Jira key in the message if the template field is absent.
    jira_field_pattern = re.compile(r'[Jj]ira:\s*([A-Z][A-Z0-9]*-\d+)')
    any_key_pattern = re.compile(r'\b([A-Z][A-Z0-9]*-\d+)\b')
    failures = []
    for wire_id in ['INTL-2026-0223', 'INTL-2026-0228']:
        found_msg = False
        for msg in messages:
            if not isinstance(msg, dict):
                continue
            text = str(msg.get('text', ''))
            if wire_id in text and 'international wire control exception filed' in text.lower():
                found_msg = True
                # Prefer the key from the explicit "Jira: KEY" field
                comp_keys = jira_field_pattern.findall(text)
                if not comp_keys:
                    # Fallback: any key that isn't an OPS- or INTL- pattern
                    all_keys = any_key_pattern.findall(text)
                    comp_keys = [k for k in all_keys
                                 if not k.upper().startswith('OPS-')
                                 and not k.upper().startswith('INTL-')]
                for ck in comp_keys:
                    if ck.upper() not in all_jira_keys:
                        failures.append(f'Ticket key {ck} referenced in Slack for {wire_id} not found in jira_state.json')
                if not comp_keys:
                    failures.append(f'No compliance ticket key found in Slack message for {wire_id}')
                break
        if not found_msg:
            failures.append(f'No qualifying #compliance-urgent message found for {wire_id}')
    if failures:
        return {'pass': False, 'score': 0.0, 'feedback': f'COMP key cross-reference issues: {failures}'}
    return {'pass': True, 'score': 1.0, 'feedback': 'COMP ticket keys in Slack messages for INTL-2026-0223 and INTL-2026-0228 all exist in jira_state.json.'}
